 * Solves the problem by simulating the generation process generation by generation (BFS).
 * 
 * @param {Point[][]} points - The initial set of points.
 * @param {Point} target - The target point to find.
 * @returns {number} The minimum generation k, or -1 if unreachable.
 */
function solve(points, target) {
    /**
     * Helper to serialize a point [x, y, z] into a string key.
     * @param {Point} p 
     * @returns {string}
     */
    const serializePoint = (p) => p.join(',');

    /**
     * Helper to deserialize a point string back into an array [x, y, z].
     * @param {string} s 
     * @returns {Point}
     */
    const deserializePoint = (s) => s.split(',').map(Number);

    /**
     * Calculates the midpoint C = [floor((x1+x2)/2), ...]
     * @param {Point} a 
     * @param {Point} b 
     * @returns {Point}
     */
    const calculateMidpoint = (a, b) => [
        Math.floor((a[0] + b[0]) / 2),
        Math.floor((a[1] + b[1]) / 2),
        Math.floor((a[2] + b[2]) / 2)
    ];

    // Convert target to string representation for quick checking
    const targetKey = serializePoint(target);

    // 1. Check Generation 0
    const initialPointKeys = new Set(points.map(serializePoint));
    if (initialPointKeys.has(targetKey)) {
        return 0;
    }

    // P_total stores all unique points found up to the previous generation (k-1).
    // We store them as strings (keys) for set management.
    let pTotalKeys = new Set(initialPointKeys);

    // Convert keys back to actual point objects for easier pairwise iteration later.
    // We store an array of objects {key: string, point: Point} to keep track of the coordinates.
    let pTotalPoints = points.map(p => ({ key: serializePoint(p), point: p }));

    let k = 1;

    while (true) {
        // If fewer than 2 points are available, no new pairs can be formed.
        if (pTotalPoints.length < 2) {
            return -1;
        }

        /** @type {Map<string, Point>} Stores newly generated points in generation k */
        const pNewGenerationK = new Map();

        // Iterate over all unique pairs (a, b) from pTotalPoints
        for (let i = 0; i < pTotalPoints.length; i++) {
            const a = pTotalPoints[i].point;

            // Start j from i + 1 to avoid redundant pairs (a, b) and self-pairs (a, a)
            for (let j = i + 1; j < pTotalPoints.length; j++) {
                const b = pTotalPoints[j].point;

                // Since pTotalPoints only contains unique coordinate points, a != b is guaranteed if i != j.
                // The problem statement requires two *different* points, which means different coordinates.
                // Since we ensure i < j, the points a and b must be distinct in coordinate space based on how pTotalPoints is built.

                const c = calculateMidpoint(a, b);
                const cKey = serializePoint(c);

                // Only consider points that are genuinely new (not already found in generations 0 to k-1)
                if (!pTotalKeys.has(cKey)) {
                    pNewGenerationK.set(cKey, c);

                    // Check if the target is found in this new generation
                    if (cKey === targetKey) {
                        return k;
                    }
                }
            }
        }

        // If no new points were generated, the target is unreachable.
        if (pNewGenerationK.size === 0) {
            return -1;
        }

        // Update state for the next iteration (k+1)

        // 1. Update P_total_Keys
        pNewGenerationK.forEach((c, key) => pTotalKeys.add(key));

